import React, { useEffect, useRef } from 'react';
import lottie from 'lottie-web';

const LottieAnimation = () => {
  const animationRef = useRef(null);
  const animationContainerRef = useRef(null);

  useEffect(() => {
    const options = {
      root: null,
      rootMargin: '0px',
      threshold: 0.5, // Adjust this threshold to control when the animation starts playing (0.5 means 50% visibility)
    };

    const handleIntersection = (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          animationRef.current.play();
        } else {
          animationRef.current.pause();
        }
      });
    };

    const observer = new IntersectionObserver(handleIntersection, options);
    observer.observe(animationContainerRef.current);

    return () => {
      observer.unobserve(animationContainerRef.current);
    };
  }, []);

  useEffect(() => {
    if (!animationRef.current) {
      // Initialize Lottie animation if it hasn't been initialized yet
      animationRef.current = lottie.loadAnimation({
        container: animationContainerRef.current,
        renderer: 'svg',
        loop: false,
        autoplay: false, // Set autoplay to false since we will start it based on intersection
        animationData: flipAnimationData(require('../resources/animation_lkuowbyo.json')), // Flip the animation data
      });
    }
  }, []);

  // Function to flip the animation data horizontally
  const flipAnimationData = (animationData) => {
    if (!animationData || !animationData.layers) return animationData;

    animationData.layers.forEach((layer) => {
      if (layer.shapes && layer.shapes[0] && layer.shapes[0].it) {
        layer.shapes[0].it.forEach((item) => {
          if (item.ks && item.ks.k && item.ks.k[0] && item.ks.k[0].v) {
            item.ks.k[0].v.forEach((point) => {
              if (point[0]) {
                point[0] = -point[0]; // Invert the x value
              }
            });
          }
        });
      }
    });

    return animationData;
  };

  return (
    <div ref={animationContainerRef} style={{ width: '300px', height: '300px' }}></div>
  );
};

export default LottieAnimation;
